changeSet.sql:
CREATE TABLE product (
    product_id SERIAL PRIMARY KEY,
    name VARCHAR(100),
    price NUMERIC(10,2),
    category VARCHAR(50)
);

CREATE TABLE men_clothing (
    size VARCHAR(10),
    fabric VARCHAR(50)
) INHERITS (product);

CREATE TABLE women_clothing (
    style VARCHAR(50),
    brand VARCHAR(50)
) INHERITS (product);

CREATE TABLE orders (
    order_id SERIAL PRIMARY KEY,
    product_id INT REFERENCES product(product_id),
    quantity INT
);
